const items = $input.all();
const wb = $('Secretary Webhook').first().json;
const action = wb.body?.action || 'unknown';
const first = items[0]?.json || {};

// Error passthrough (unknown action or explicit error)
if (first.success === false || first.error) {
  return [{ json: { success: false, action, error: first.error } }];
}

// Graph API responses with { value: [...] }
if (first.value && Array.isArray(first.value)) {
  return [{ json: { success: true, action, count: first.value.length, data: first.value } }];
}

// sendMail / forward return 202 No Content
if (['send', 'forward'].includes(action) && !first.id) {
  return [{ json: { success: true, action, message: `${action} completed successfully` } }];
}

// create_draft returns the new message object
if (action === 'create_draft' && first.id) {
  return [{ json: { success: true, action, message: 'Draft saved', data: first } }];
}

// delete / move / mark / flag return empty or minimal
if (['delete', 'move', 'mark', 'flag'].includes(action) && (items.length === 0 || !first.id)) {
  return [{ json: { success: true, action, message: `${action} completed successfully` } }];
}

// calendar_create returns the new event
if (action === 'calendar_create' && first.id) {
  return [{ json: { success: true, action, message: 'Event created', data: first } }];
}

// list (getAll) returns multiple items — one n8n item per email
if (items.length > 1) {
  return [{ json: { success: true, action, count: items.length, data: items.map(i => i.json) } }];
}

// get / reply / single result
return [{ json: { success: true, action, data: first } }];

